module top_module(
    input [3:0] a,
    input [3:0] b,
    input [1:0] opcode,
    output [3:0] result
);reg [3:0] invalid_result;

always @(*) begin
    case(opcode)
        2'b00: invalid_result = a + b;
        2'b01: invalid_result = a - b;
        2'b10: invalid_result = a & b;
        2'b11: invalid_result = a | b;
    endcase
end

assign result = invalid_result;

endmodule
